&quot; aria-label=&quot;Resolved&quot; title=&quot;Topic is resolved.&quot;&gt;&lt;/span&gt;NGINX CVE-2026-42945 Rewrite Rules\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://wordpress.org/support/topic/nginx-cve-2026-42945-rewrite-rules/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 19 May 2026 08:58:32 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2089:\"\n						\n						<p>Replies: 1</p>\n						<p class=\"wp-block-paragraph\">Hi, a few days ago, an 18-year-old vulnerability in NGINX—specifically concerning the Rewrite module—was patched. This is particularly relevant in conjunction with <code>$1/$2</code>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In the plugin settings, you currently specify…</p>\n\n\n\n<p class=\"wp-block-paragraph\"><code></code><code>rewrite ^/.*-misc?\\.xml$ \"/index.php?xml_sitemap=params=$2\" last;<br />rewrite ^/.*-misc?\\.xml\\.gz$ \"/index.php?xml_sitemap=params=$2;zip=true\" last;<br />rewrite ^/.*-misc?\\.html$ \"/index.php?xml_sitemap=params=$2;html=true\" last;<br />rewrite ^/.*-misc?\\.html\\.gz$ \"/index.php?xml_sitemap=params=$2;html=true;zip=true\" last;<br />rewrite ^/.*-sitemap.*(?:\\d\\{1,4\\}(?!-misc)|-misc)?\\.xml$ \"/index.php?xml_sitemap=params=$2\" last;<br />rewrite ^/.*-sitemap.*(?:\\d\\{1,4\\}(?!-misc)|-misc)?\\.xml\\.gz$ \"/index.php?xml_sitemap=params=$2;zip=true\" last;<br />rewrite ^/.*-sitemap.*(?:\\d\\{1,4\\}(?!-misc)|-misc)?\\.html$ \"/index.php?xml_sitemap=params=$2;html=true\" last;<br />rewrite ^/.*-sitemap.*(?:\\d\\{1,4\\}(?!-misc)|-misc)?\\.html\\.gz$ \"/index.php?xml_sitemap=params=$2;html=true;zip=true\" last;</code></p>\n\n\n\n<p class=\"wp-block-paragraph\">It should look more like this now.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><code>rewrite \"^/(?.<em>)-misc.xml$\" \"/index.php?xml_sitemap=params=$slug\" last; rewrite \"^/(?.</em>)-misc.xml.gz$\" \"/index.php?xml_sitemap=params=$slug;zip=true\" last;<br />rewrite \"^/(?.<em>)-misc.html$\" \"/index.php?xml_sitemap=params=$slug;html=true\" last; rewrite \"^/(?.</em>)-misc.html.gz$\" \"/index.php?xml_sitemap=params=$slug;html=true;zip=true\" last;<br />rewrite \"^/(?.<em>)-sitemap.</em>.xml$\" \"/index.php?xml_sitemap=params=$slug\" last;<br />rewrite \"^/(?.<em>)-sitemap.</em>.xml.gz$\" \"/index.php?xml_sitemap=params=$slug;zip=true\" last;<br />rewrite \"^/(?.<em>)-sitemap.</em>.html$\" \"/index.php?xml_sitemap=params=$slug;html=true\" last;<br />rewrite \"^/(?.<em>)-sitemap.</em>.html.gz$\" \"/index.php?xml_sitemap=params=$slug;html=true;zip=true\" last;</code></p>\n						\n					\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"saguya\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:67:\"\n					\n					\n					\n					\n					\n\n					\n					\n\n					\n					\n					\n				\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://wordpress.org/support/topic/add-google-news-xml/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:19:\"Add Google News XML\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://wordpress.org/support/topic/add-google-news-xml/\";s:7:\"attribs\";a:0:{}s:8:\"xm