,(1049,160,'seo_titulo','Quiénes somos — REDIMAG'),(1050,160,'_seo_titulo','field_seo_titulo'),(1051,160,'seo_descripcion','REDIMAG es una red especializada en insumos veterinarios y agropecuarios en Colombia. Conoce nuestro equipo, valores y compromiso con el sector salud animal.'),(1052,160,'_seo_descripcion','field_seo_descripcion'),(1053,160,'seo_imagen_og',''),(1054,160,'_seo_imagen_og','field_seo_imagen_og');
